aws_iam_policy_document.bp_s3_replicatio.terraform_block:
data "aws_iam_policy_document" "bp_s3_replication_pol_doc" {
  count = var.bp_replication != null ? 1 : 0

  statement {
    effect  = "Allow"
    actions = ["sts:AssumeRole"]
    principals {
      identifiers = [
        "s3.amazonaws.com"
      ]
      type = "Service"
    }
    principals {
      type        = "AWS"
