}

aws_iam_policy_document.combined_policy.terraform_block:
data "aws_iam_policy_document" "combined_policy" {
  override_policy_documents = compact([
    var.bucket_policy_document.primary,
    try(data.aws_iam_policy_document.inventory_policy[0].json, null)
  ])

  statement {
    sid       = "DenyNonSSLRequests"
    actions   = ["s3:*"]
    effect    = "Deny"
    resources = [aws_s3_bucket.bucket.arn, "${aws_s3_bucket.bucket.arn}/*"]

    condition {
      test     = "Bool"
      variable = "aws:SecureTransport"
      values   = ["false"]
    }

    principals {
      type        = "AWS"
      identifiers = ["*"]
    }
  }

  provider = aws.service-primary
}

aws_iam_policy_document.combined_policy_.terraform_block:
