aws_iam_policy_document.consumers.terraform_block:
data "aws_iam_policy_document" "consumers" {
  for_each = var.consumer_policy_actions

  policy_id = replace(each.key, "/[^a-zA-Z0-9]/", "")

  statement {
    effect  = "Allow"
    sid     = replace(each.key, "/[^a-zA-Z0-9]/", "")
    actions = each.value

    resources = [
      aws_s3_bucket.bucket.arn,
      "${aws_s3_bucket.bucket.arn}/*",
    ]
  }

  provider = aws.service-primary
}

aws_iam_policy_document.trusted-policy-d.terraform_block:
data "aws_iam_policy_document" "trusted-policy-databricks_bucket" {
  count = var.enable_databricks ? 1 : 0

  statement {
    effect  = "Allow"
    actions = ["sts:AssumeRole"]

    principals {
      type = "AWS"
      identifiers = [
        "arn:aws:iam::414351767826:role/unity-catalog-prod-UCMasterRole-14S5ZJVK0TYTL"
      ]
    }

    condition {
      test     = "StringEquals"
      variable = "sts:ExternalId"
      values   = [var.databricks_external_id]
    }
  }

  statement {
    effect  = "Allow"
    actions = ["sts:AssumeRole"]

    principals {
      type        = "AWS"
      identifiers = ["*"]
    }

    condition {
      test     = "ArnLike"
      variable = "aws:PrincipalArn"
      values   = ["arn:aws:iam::${data.aws_caller_identity.main.account_id}:role/${local.databricks_role_name}"]
    }
  }

  provider = aws.service-primary
}

